// ExportStudioProject streams a ZIP of the workspace to the client.
// Skips node_modules and .git. Resolves paths safely so no traversal is possible.
func ExportStudioProject(c *gin.Context) {
	sessionID := strings.TrimSpace(c.Query("session_id"))
	userID := strings.TrimSpace(c.Query("user_id"))
	workspaceName := strings.TrimSpace(c.Query("workspace_name"))

	if sessionID == "" || userID == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "session_id and user_id are required"})
		return
	}

	storageRoot := filepath.Join("/var/storage", userID, sessionID)
	resolved, ok := ensurePathUnderRoot("/var/storage", filepath.Join(userID, sessionID))
	if !ok {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid session path"})
		return
	}
	if info, err := os.Stat(resolved); err != nil || !info.IsDir() {
		c.JSON(http.StatusNotFound, gin.H{"error": "workspace not found"})
		return
	}

	fileName := workspaceName
	if fileName == "" {
		fileName = sessionID
	}
	c.Header("Content-Type", "application/zip")
	c.Header("Content-Disposition", fmt.Sprintf(`attachment; filename="%s.zip"`, fileName))

	zipWriter := zip.NewWriter(c.Writer)
	defer zipWriter.Close()

	walkErr := filepath.Walk(storageRoot, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if info.IsDir() {
			if info.Name() == "node_modules" || info.Name() == ".git" {
				return filepath.SkipDir
			}
			return nil
		}

		rel, relErr := filepath.Rel(storageRoot, path)
		if relErr != nil {
			return relErr
		}
		rel = strings.ReplaceAll(rel, "\\", "/")

		src, openErr := os.Open(path)
		if openErr != nil {
			return openErr
		}
		defer src.Close()

		dst, createErr := zipWriter.Create(rel)
		if createErr != nil {
			return createErr
		}
		if _, copyErr := io.Copy(dst, src); copyErr != nil {
			return copyErr
		}
		return nil
	})
	if walkErr != nil {
		applog.Errorf("export walk failed: %v", walkErr)
		// Headers already flushed — best-effort: caller will receive a truncated zip.
		return
	}
}

// HandleDevServerLogs tails .devserver.log and streams lines via SSE until the
// client disconnects. Poll loop (100ms) beats adding an fs-watcher dependency.
func HandleDevServerLogs(c *gin.Context) {
	storagePath := c.Query("storage_path")
	if storagePath == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "storage_path is required"})
		return
	}
	logPath, ok := ensurePathUnderRoot(storagePath, ".devserver.log")
	if !ok {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid storage_path"})
		return
	}

	c.Header("Content-Type", "text/event-stream")
	c.Header("Cache-Control", "no-cache")
	c.Header("Connection", "keep-alive")
	c.Header("X-Accel-Buffering", "no")

	f, err := os.Open(logPath)
	if err != nil {
		fmt.Fprintf(c.Writer, "event: error\ndata: %s\n\n", err.Error())
		c.Writer.Flush()
		return
	}
	defer f.Close()

	// Start reading from the end so we only emit new lines.
	if _, err := f.Seek(0, io.SeekEnd); err != nil {
		applog.Warnf("seek end failed: %v", err)
	}

	reader := bufio.NewReader(f)
	ctx := c.Request.Context()
	ticker := time.NewTicker(100 * time.Millisecond)
	defer ticker.Stop()

	// Heartbeat so proxies don't kill the idle connection.
	heartbeat := time.NewTicker(15 * time.Second)
	defer heartbeat.Stop()

	for {
		select {
		case <-ctx.Done():
			return
		case <-heartbeat.C:
			fmt.Fprint(c.Writer, ": ping\n\n")
			c.Writer.Flush()
		case <-ticker.C:
			for {
				line, rerr := reader.ReadString('\n')
				if line != "" {
					line = strings.TrimRight(line, "\n")
					fmt.Fprintf(c.Writer, "data: %s\n\n", line)
					c.Writer.Flush()
				}
				if rerr == io.EOF {
					break
				}
				if rerr != nil {
					fmt.Fprintf(c.Writer, "event: error\ndata: %s\n\n", rerr.Error())
					c.Writer.Flush()
					return
				}
			}
		}
	}
}

// ensurePathUnderRoot returns the absolute resolved path of `sub` under `root`
// and reports whether it stays inside the root. It resolves symlinks via
// filepath.EvalSymlinks when the target exists so a symlink-escape is caught.
func ensurePathUnderRoot(root, sub string) (string, bool) {
	if root == "" {
		return "", false
	}
	absRoot, err := filepath.Abs(root)
	if err != nil {
		return "", false
	}
	// Reject absolute sub-paths outright — the intent is always "relative to root".
	if filepath.IsAbs(sub) {
		return "", false
	}

	joined := filepath.Join(absRoot, sub)
	cleaned := filepath.Clean(joined)

	rel, err := filepath.Rel(absRoot, cleaned)
	if err != nil {
		return "", false
	}
	if rel == ".." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) {
		return "", false
	}

	// If the target exists, resolve symlinks and re-check containment.
	if _, statErr := os.Lstat(cleaned); statErr == nil {
		if resolved, evalErr := filepath.EvalSymlinks(cleaned); evalErr == nil {
			rel2, relErr := filepath.Rel(absRoot, resolved)
			if relErr != nil || rel2 == ".." || strings.HasPrefix(rel2, ".."+string(filepath.Separator)) {
				return "", false
			}
			return resolved, true
		}
	}
	return cleaned, true
}

