func WriteStudioFile(c *gin.Context) {
	var req struct {
		StoragePath      string `json:"storage_path" binding:"required"`
		FilePath         string `json:"file_path" binding:"required"`
		Content          string `json:"content"`
		AllowDestructive bool   `json:"allow_destructive"`
		SkipReload       bool   `json:"skip_reload"`
	}
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	fullPath, ok := ensurePathUnderRoot(req.StoragePath, req.FilePath)
	if !ok {
		c.JSON(http.StatusBadRequest, gin.H{"error": "file_path must be under storage_path"})
		return
	}
	if err := os.WriteFile(fullPath, []byte(req.Content), 0644); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "success"})
}

