import { useCallback, useEffect, useRef, useState } from 'react';

export type LogLevel = 'info' | 'warn' | 'error';

export interface LogEntry {
  id: string;
  level: LogLevel;
  message: string;
  ts: number;
}

const MAX_LOGS = 5000;

function inferLevel(msg: string): LogLevel {
  const m = msg.toLowerCase();
  if (m.includes('error') || m.includes('exception') || m.includes('trace')) return 'error';
  if (m.includes('warn') || m.includes('deprecated')) return 'warn';
  return 'info';
}

export function useSSELogStream(
  url: string | null,
  enabled: boolean,
  readinessProbe?: () => Promise<boolean>,
): {
  logs: LogEntry[];
  connected: boolean;
  clear: () => void;
} {
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [connected, setConnected] = useState(false);
  const esRef = useRef<EventSource | null>(null);
  const cancelledRef = useRef(false);

  const clear = useCallback(() => setLogs([]), []);

  useEffect(() => {
    cancelledRef.current = false;
    if (!url || !enabled) {
      return;
    }

    let stopped = false;

    async function open() {
      if (readinessProbe) {
        // Poll the probe until it resolves true or the effect is cancelled.
        for (let i = 0; i < 120 && !stopped; i++) {
          try {
            if (await readinessProbe()) break;
          } catch {
            /* keep polling */
          }
          await new Promise((r) => setTimeout(r, 500));
        }
        if (stopped) return;
      }

      const es = new EventSource(url as string);
      esRef.current = es;

      es.onopen = () => setConnected(true);
      es.onerror = () => setConnected(false);
      es.onmessage = (evt) => {
        const msg = typeof evt.data === 'string' ? evt.data : '';
        const entry: LogEntry = {
          id: `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
          level: inferLevel(msg),
          message: msg,
          ts: Date.now(),
        };
        setLogs((prev) => (prev.length >= MAX_LOGS ? [...prev.slice(-MAX_LOGS + 1), entry] : [...prev, entry]));
      };
    }

    void open();

    return () => {
      stopped = true;
      setConnected(false);
      esRef.current?.close();
      esRef.current = null;
    };
  }, [url, enabled, readinessProbe]);

  return { logs, connected, clear };
}

export const MIN_STUDIO_SESSION_ID_LEN = 16;

const SESSION_ID_RE = /^[a-zA-Z0-9._-]+$/;

/**
 * Returns a 32-char hex session id.
 * Prefers crypto.getRandomValues (all modern browsers + Node 18+);
 * falls back to Math.random only when the crypto API is unavailable.
 */
export function generateStudioSessionId(): string {
  const bytes = new Uint8Array(16);
  const c: Crypto | undefined =
    typeof globalThis !== 'undefined' ? (globalThis as typeof globalThis & { crypto?: Crypto }).crypto : undefined;

  if (c && typeof c.getRandomValues === 'function') {
    c.getRandomValues(bytes);
  } else {
    for (let i = 0; i < bytes.length; i++) {
      bytes[i] = Math.floor(Math.random() * 256);
    }
  }

  let out = '';
  for (let i = 0; i < bytes.length; i++) {
    out += bytes[i].toString(16).padStart(2, '0');
  }
  return out;
}

export function isValidStudioSessionId(id: string | null | undefined): boolean {
  if (!id) return false;
  if (id.length < MIN_STUDIO_SESSION_ID_LEN) return false;
  return SESSION_ID_RE.test(id);
}

