import React, { useMemo, useState } from 'react';
import { ChevronDown, ChevronRight, File as FileIcon, Folder as FolderIcon } from 'lucide-react';

export interface FileNode {
  path: string;
  name: string;
  type: 'file' | 'folder';
  children?: FileNode[];
}

interface StudioFileExplorerProps {
  root: FileNode;
  selectedPath?: string;
  defaultExpanded?: boolean;
  onFileSelect: (path: string) => void;
}

export default function StudioFileExplorer({
  root,
  selectedPath,
  defaultExpanded = true,
  onFileSelect,
}: StudioFileExplorerProps) {
  const [expanded, setExpanded] = useState<Set<string>>(
    () => new Set(defaultExpanded ? [root.path] : []),
  );

  const toggle = (path: string) => {
    setExpanded((prev) => {
      const next = new Set(prev);
      if (next.has(path)) next.delete(path);
      else next.add(path);
      return next;
    });
  };

  const renderNode = (node: FileNode, level: number): React.ReactNode => {
    const isSelected = node.path === selectedPath;
    const rowClass = `flex items-center gap-1.5 px-2 py-0.5 cursor-pointer select-none text-[13px] ${
      isSelected ? 'bg-[#0e639c] text-white' : 'text-[#cccccc] hover:bg-white/5'
    }`;
    const pad = { paddingLeft: 8 + level * 12 };

    if (node.type === 'folder') {
      const open = expanded.has(node.path);
      return (
        <div key={node.path}>
          <div className={rowClass} style={pad} onClick={() => toggle(node.path)}>
            {open ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
            <FolderIcon size={14} />
            <span className="truncate">{node.name}</span>
          </div>
          {open && node.children?.map((child) => renderNode(child, level + 1))}
        </div>
      );
    }

    return (
      <div
        key={node.path}
        className={rowClass}
        style={pad}
        onClick={() => onFileSelect(node.path)}
      >
        <span style={{ width: 14 }} />
        <FileIcon size={14} />
        <span className="truncate">{node.name}</span>
      </div>
    );
  };

  const tree = useMemo(() => renderNode(root, 0), [root, expanded, selectedPath]);

  return (
    <div className="h-full overflow-y-auto bg-[#1e1e1e] border-r border-[#3e3e3e] py-1">
      {tree}
    </div>
  );
}

'use client';

import dynamic from 'next/dynamic';
import { useEffect, useMemo, useRef } from 'react';

const MonacoEditor = dynamic(() => import('@monaco-editor/react').then((m) => m.default), {
  ssr: false,
});

const EXT_TO_LANGUAGE: Record<string, string> = {
  ts: 'typescript',
  tsx: 'typescript',
  js: 'javascript',
  jsx: 'javascript',
  py: 'python',
  go: 'go',
  rs: 'rust',
  json: 'json',
  css: 'css',
  html: 'html',
  md: 'markdown',
  yaml: 'yaml',
  yml: 'yaml',
  sh: 'shell',
};

function languageFor(path: string): string {
  const dot = path.lastIndexOf('.');
  if (dot < 0) return 'plaintext';
  return EXT_TO_LANGUAGE[path.slice(dot + 1).toLowerCase()] ?? 'plaintext';
}

export interface StudioCodeEditorProps {
  value: string;
  path: string;
  isDark?: boolean;
  onChange: (next: string) => void;
}

export default function StudioCodeEditor({
  value,
  path,
  isDark = true,
  onChange,
}: StudioCodeEditorProps) {
  const language = useMemo(() => languageFor(path), [path]);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => () => {
    if (debounceRef.current) clearTimeout(debounceRef.current);
  }, []);

  const handleChange = (next: string | undefined) => {
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => onChange(next ?? ''), 150);
  };

  return (
    <MonacoEditor
      value={value}
      path={path}
      language={language}
      theme={isDark ? 'vs-dark' : 'vs'}
      onChange={handleChange}
      options={{
        fontSize: 13,
        fontFamily: "'JetBrains Mono', ui-monospace, monospace",
        minimap: { enabled: false },
        wordWrap: 'on',
        scrollBeyondLastLine: false,
        tabSize: 2,
        automaticLayout: true,
      }}
    />
  );
}

