export interface StudioAgentChatRequest {
  query: string;
  agent?: string;
  model?: string;
  user_id?: string;
  session_id?: string;
  context?: Record<string, string>;
}

export interface StudioAgentChatResponse {
  response: string;
  agent_type: string;
  session_id: string;
  conversation_id: string;
  status: 'ok' | 'error';
  error?: string;
}

export class StudioAgentChatError extends Error {
  readonly kind: 'network' | 'http' | 'parse' | 'timeout';
  readonly status?: number;
  constructor(kind: StudioAgentChatError['kind'], message: string, status?: number) {
    super(message);
    this.name = 'StudioAgentChatError';
    this.kind = kind;
    this.status = status;
  }
}

const DEFAULT_TIMEOUT_MS = 30_000;

export async function sendStudioAgentChat(
  baseUrl: string,
  request: StudioAgentChatRequest,
  options: { timeoutMs?: number; signal?: AbortSignal } = {},
): Promise<StudioAgentChatResponse> {
  const url = `${baseUrl.replace(/\/$/, '')}/api/v2/studio/agent/chat`;
  const controller = new AbortController();
  const timeoutMs = options.timeoutMs ?? DEFAULT_TIMEOUT_MS;
  const timeout = setTimeout(() => controller.abort(), timeoutMs);
  if (options.signal) {
    options.signal.addEventListener('abort', () => controller.abort(), { once: true });
  }

  let res: Response;
  try {
    res = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(request),
      signal: controller.signal,
    });
  } catch (err) {
    clearTimeout(timeout);
    const msg = err instanceof Error ? err.message : String(err);
    if ((err as Error).name === 'AbortError') {
      throw new StudioAgentChatError('timeout', `chat request timed out after ${timeoutMs}ms`);
    }
    throw new StudioAgentChatError('network', msg);
  }
  clearTimeout(timeout);

  if (!res.ok) {
    let bodyText = '';
    try { bodyText = await res.text(); } catch { /* ignore */ }
    throw new StudioAgentChatError('http', `agent/chat ${res.status}: ${bodyText.slice(0, 200)}`, res.status);
  }

  try {
    return (await res.json()) as StudioAgentChatResponse;
  } catch (err) {
    throw new StudioAgentChatError('parse', 'agent/chat returned invalid JSON');
  }
}

