package studio

import (
	"os"
	"path/filepath"
	"testing"
)

func TestEnsurePathUnderRoot(t *testing.T) {
	root := t.TempDir()
	// Seed a sibling dir outside the root to test symlink-escape detection.
	sibling := t.TempDir()
	if err := os.MkdirAll(sibling, 0o755); err != nil {
		t.Fatalf("mkdir sibling: %v", err)
	}

	// Create a safe file in the root.
	safe := filepath.Join(root, "ok.txt")
	if err := os.WriteFile(safe, []byte("ok"), 0o644); err != nil {
		t.Fatalf("write seed: %v", err)
	}

	// Symlink pointing outside — filepath.EvalSymlinks should catch it.
	escape := filepath.Join(root, "escape")
	if err := os.Symlink(sibling, escape); err != nil {
		t.Skipf("symlink not supported on this platform: %v", err)
	}

	cases := []struct {
		name    string
		sub     string
		wantOK  bool
	}{
		{"simple file", "ok.txt", true},
		{"nested ok", "sub/inner/file.go", true},
		{"parent escape", "../etc/passwd", false},
		{"deep parent escape", "sub/../../../etc/passwd", false},
		{"absolute sub rejected", "/etc/passwd", false},
		{"empty sub treated as root itself", "", true},
		{"symlink escape", "escape/anywhere", false},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			resolved, ok := ensurePathUnderRoot(root, tc.sub)
			if ok != tc.wantOK {
				t.Fatalf("got ok=%v, want %v (resolved=%q)", ok, tc.wantOK, resolved)
			}
			if ok && !filepath.IsAbs(resolved) {
				t.Fatalf("expected absolute resolved path, got %q", resolved)
			}
		})
	}
}

