export function loadWorkspaces(userId?: string): Workspace[] {
  if (!userId) return [];
  if (typeof localStorage === 'undefined') return [];

  const raw = localStorage.getItem(`ws:${userId}`);
  if (!raw) return [];

  try {
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? (parsed as Workspace[]) : [];
  } catch {
    return [];
  }
}

const MAX_BRANCH_LEN = 50;

export function toBranchName(prompt: string): string {
  const cleaned = prompt
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  const slug = cleaned.split(' ').slice(0, 6).join('-') || 'change';
  const full = `feat/${slug}`;
  return full.slice(0, MAX_BRANCH_LEN).replace(/-+$/g, '');
}
